import{_ as e,o as t,c as i,a2 as r}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"上传类型与内容校验、权限、病毒扫描与审计","description":"","frontmatter":{"stage":"intermediate","direction":"backend-data","topic":"upload-security"},"headers":[],"relativePath":"05-backend-data/notes/07-cache-messaging-storage/18-upload-security-scan-audit.md","filePath":"05-backend-data/notes/07-cache-messaging-storage/18-upload-security-scan-audit.md","lastUpdated":null}'),n={name:"05-backend-data/notes/07-cache-messaging-storage/18-upload-security-scan-audit.md"};function l(o,a,d,c,s,p){return t(),i("div",null,[...a[0]||(a[0]=[r(`<h1 id="上传类型与内容校验、权限、病毒扫描与审计" tabindex="-1">上传类型与内容校验、权限、病毒扫描与审计 <a class="header-anchor" href="#上传类型与内容校验、权限、病毒扫描与审计" aria-label="Permalink to &quot;上传类型与内容校验、权限、病毒扫描与审计&quot;">​</a></h1><p>文件上传是不可信字节进入存储和解析器的入口。安全链路要限制大小与速率、验证magic和结构、隔离未扫描对象、使用最小权限扫描器、阻止主动内容执行，并保留可追踪审计。</p><h2 id="_1-数据流与责任边界" tabindex="-1">1. 数据流与责任边界 <a class="header-anchor" href="#_1-数据流与责任边界" aria-label="Permalink to &quot;1. 数据流与责任边界&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> A[&quot;客户端/生产者&quot;] --&gt; B[&quot;授权与受控元数据&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> B --&gt; C[&quot;对象存储&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> C --&gt; D[&quot;异步处理/验证&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> D --&gt; E[&quot;业务发布与审计&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>上传对象必须先处于存储层不可下载的 quarantine 状态。发布条件应绑定精确 object version、内容识别结果、扫描引擎与规则版本；扩展名、客户端 Content-Type 或一次“未发现恶意”都不能单独证明文件安全。</p><h2 id="_2-大小限制" tabindex="-1">2. 大小限制 <a class="header-anchor" href="#_2-大小限制" aria-label="Permalink to &quot;2. 大小限制&quot;">​</a></h2><p>机制：网关、预签policy、对象HEAD和解压后分别限制。</p><p>使用：防内存/存储/压缩炸弹。</p><p>失败：只信Content-Length。</p><p>验证：超限/分块/缺header测试。</p><p>取舍：多层校验增加实现但封闭绕过。</p><p>围绕 大小限制 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_3-文件名" tabindex="-1">3. 文件名 <a class="header-anchor" href="#_3-文件名" aria-label="Permalink to &quot;3. 文件名&quot;">​</a></h2><p>机制：只作显示metadata，服务端生成随机key。</p><p>使用：避免路径、控制字符和覆盖。</p><p>失败：把../../name作为object key/Content-Disposition。</p><p>验证：规范化和安全编码测试。</p><p>取舍：保留原名利于用户但需最小化。</p><p>围绕 文件名 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_4-content-type" tabindex="-1">4. Content-Type <a class="header-anchor" href="#_4-content-type" aria-label="Permalink to &quot;4. Content-Type&quot;">​</a></h2><p>机制：客户端声明仅作提示。</p><p>使用：下载表现和初步路由。</p><p>失败：把image/png当真实性证明。</p><p>验证：magic bytes+结构解析。</p><p>取舍：严格类型可能拒绝边界格式。</p><p>围绕 Content-Type 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_5-magic-结构" tabindex="-1">5. Magic/结构 <a class="header-anchor" href="#_5-magic-结构" aria-label="Permalink to &quot;5. Magic/结构&quot;">​</a></h2><p>机制：读取受限头和安全解析器验证格式。</p><p>使用：识别伪装文件与损坏。</p><p>失败：仅扩展名白名单。</p><p>验证：构造polyglot/truncated样本。</p><p>取舍：解析器本身有漏洞面。</p><p>围绕 Magic/结构 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_6-quarantine" tabindex="-1">6. Quarantine <a class="header-anchor" href="#_6-quarantine" aria-label="Permalink to &quot;6. Quarantine&quot;">​</a></h2><p>机制：未扫描对象与公开/业务可见区隔离。</p><p>使用：阻止异步窗口暴露。</p><p>失败：上传后立即生成公共URL。</p><p>验证：策略证明app不能读quarantine。</p><p>取舍：多一次copy/状态管理。</p><p>围绕 Quarantine 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_7-malware-scan" tabindex="-1">7. Malware scan <a class="header-anchor" href="#_7-malware-scan" aria-label="Permalink to &quot;7. Malware scan&quot;">​</a></h2><p>机制：隔离worker读取并扫描，结果带engine/signature version。</p><p>使用：发现已知恶意内容。</p><p>失败：扫描成功等于永久安全。</p><p>验证：EICAR/超时/引擎更新后重扫。</p><p>取舍：不能发现全部未知威胁。</p><p>围绕 Malware scan 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_8-archive-safety" tabindex="-1">8. Archive safety <a class="header-anchor" href="#_8-archive-safety" aria-label="Permalink to &quot;8. Archive safety&quot;">​</a></h2><p>机制：限制层数、文件数、总解压大小、压缩比和路径。</p><p>使用：防zip bomb/zip slip。</p><p>失败：直接解压到共享目录。</p><p>验证：恶意archive corpus和资源限制。</p><p>取舍：限制可能拒绝合法大包。</p><p>围绕 Archive safety 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_9-active-content" tabindex="-1">9. Active content <a class="header-anchor" href="#_9-active-content" aria-label="Permalink to &quot;9. Active content&quot;">​</a></h2><p>机制：SVG/HTML/PDF/Office可包含脚本、链接或宏。</p><p>使用：隔离域下载、转码/消毒。</p><p>失败：同源inline展示用户HTML/SVG。</p><p>验证：CSP、Content-Disposition、独立origin测试。</p><p>取舍：转码损失特性但降低风险。</p><p>围绕 Active content 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_10-权限" tabindex="-1">10. 权限 <a class="header-anchor" href="#_10-权限" aria-label="Permalink to &quot;10. 权限&quot;">​</a></h2><p>机制：上传、扫描、发布、下载使用不同身份和prefix。</p><p>使用：最小权限与职责分离。</p><p>失败：扫描器拥有全桶删除。</p><p>验证：策略测试和CloudTrail/审计。</p><p>取舍：角色更多但缩小爆炸半径。</p><p>围绕 权限 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_11-审计" tabindex="-1">11. 审计 <a class="header-anchor" href="#_11-审计" aria-label="Permalink to &quot;11. 审计&quot;">​</a></h2><p>机制：记录actor、upload、object version、checksum、scan和发布决策。</p><p>使用：追责、重新扫描和删除。</p><p>失败：记录签名URL/token/完整PII。</p><p>验证：按upload ID关联并脱敏。</p><p>取舍：存储与隐私保留需平衡。</p><p>围绕 审计 的接口必须保存受控 object ID、tenant、版本和状态；客户端提供的 bucket、key、类型或结果只能作为待验证输入。</p><h2 id="_12-方案比较" tabindex="-1">12. 方案比较 <a class="header-anchor" href="#_12-方案比较" aria-label="Permalink to &quot;12. 方案比较&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>收益</th><th>边界</th></tr></thead><tbody><tr><td>同步扫描</td><td>用户立即得结果</td><td>请求超时/大文件</td></tr><tr><td>异步quarantine</td><td>可扩展隔离</td><td>状态机复杂</td></tr><tr><td>原文件下载</td><td>保真</td><td>主动内容风险</td></tr><tr><td>转码后发布</td><td>统一安全格式</td><td>质量/功能损失</td></tr><tr><td>杀毒签名</td><td>已知威胁</td><td>不能证明绝对安全</td></tr></tbody></table><h2 id="_13-完整案例-企业附件上传" tabindex="-1">13. 完整案例：企业附件上传 <a class="header-anchor" href="#_13-完整案例-企业附件上传" aria-label="Permalink to &quot;13. 完整案例：企业附件上传&quot;">​</a></h2><h3 id="输入与约束" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>PDF/Office最大100MiB，扫描期间不可下载，tenant严格隔离。</p><h3 id="处理步骤" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>API创建upload记录与quarantine随机key。</li><li>直传后服务端HEAD校验size/checksum并识别真实类型。</li><li>scanner用只读quarantine+写clean权限扫描，宏文件按策略隔离。</li><li>通过后数据库条件迁移state并发布固定object version。</li><li>下载API重新授权并签clean version，审计全链路。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>只有clean且授权对象可下载，扫描结果可按引擎版本重查。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>EICAR、伪扩展、超大、扫描timeout、跨tenant、旧worker发布均被阻止。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>扫描前业务表直接引用对象会被猜测下载；quarantine policy必须从存储层拒绝。</p><h3 id="恢复要求" tabindex="-1">恢复要求 <a class="header-anchor" href="#恢复要求" aria-label="Permalink to &quot;恢复要求&quot;">​</a></h3><p>扫描任务以 object version 和扫描策略版本幂等；超时或引擎不可用时对象继续隔离，不降级为 clean。worker 只有在 generation 仍匹配时才能条件发布，旧结果不得覆盖重新上传的新版本；引擎或规则升级后可为仍保留的版本安排重扫。</p><h2 id="_14-完整案例-压缩包导入" tabindex="-1">14. 完整案例：压缩包导入 <a class="header-anchor" href="#_14-完整案例-压缩包导入" aria-label="Permalink to &quot;14. 完整案例：压缩包导入&quot;">​</a></h2><h3 id="输入与约束-1" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束-1" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>ZIP包含CSV/图片，最多1000文件、解压2GiB、层数2，不能路径穿越。</p><h3 id="处理步骤-1" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤-1" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>隔离容器无网络/低权限解析。</li><li>逐entry规范化路径，拒绝绝对路径、..、symlink和设备文件。</li><li>流式累计文件数、未压缩字节、压缩比和深度。</li><li>每个文件单独类型/病毒校验，不执行宏/脚本。</li><li>验证全部后事务创建导入任务，临时文件生命周期清理。</li></ol><h3 id="输出-1" tabindex="-1">输出 <a class="header-anchor" href="#输出-1" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>恶意包在资源上限内失败，合法包产生明确清单。</p><h3 id="验证-1" tabindex="-1">验证 <a class="header-anchor" href="#验证-1" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>zip slip、zip bomb、嵌套、重名、Unicode路径和损坏CRC样本。</p><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>先完整解压再检查上限会先耗尽磁盘；限制必须在流式写入前/过程中。</p><h3 id="恢复要求-1" tabindex="-1">恢复要求 <a class="header-anchor" href="#恢复要求-1" aria-label="Permalink to &quot;恢复要求&quot;">​</a></h3><p>导入任务绑定不可变压缩包 version，并持久化已验证 entry 清单与资源计数。失败后删除该 job ID 的临时解压空间并从原包重新验证；全部 entry 通过前不创建可见业务数据。失败清单保留受限审计信息，便于区分路径穿越、炸弹阈值、CRC 与恶意内容。</p><h2 id="_15-故障注入矩阵" tabindex="-1">15. 故障注入矩阵 <a class="header-anchor" href="#_15-故障注入矩阵" aria-label="Permalink to &quot;15. 故障注入矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>注入</th><th>预期</th><th>禁止</th></tr></thead><tbody><tr><td>签名后撤权</td><td><code>upload_rejected_size</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>上传中断</td><td><code>type_mismatch</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>同key并发写</td><td><code>scan_queue_age</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>checksum错误</td><td><code>scan_timeout</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>扫描器崩溃</td><td><code>malware_detected</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>生命周期延迟</td><td><code>quarantine_bytes</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>对象存储429/503</td><td><code>publish_conflict</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr><tr><td>数据库提交后断线</td><td><code>download_denied</code> 可观察且状态可恢复</td><td>越权发布、静默损坏或无限重试</td></tr></tbody></table><h2 id="_16-调试与观测" tabindex="-1">16. 调试与观测 <a class="header-anchor" href="#_16-调试与观测" aria-label="Permalink to &quot;16. 调试与观测&quot;">​</a></h2><ol><li><code>upload_rejected_size</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>type_mismatch</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>scan_queue_age</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>scan_timeout</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>malware_detected</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>quarantine_bytes</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>publish_conflict</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>download_denied</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>archive_limit</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li><li><code>audit_gap</code>：按环境、操作和低基数结果分类，定义单位、采样点、SLO与告警窗口。</li></ol><p>按 upload ID 依次核对 object version/checksum、magic/结构识别、quarantine policy、扫描 attempt、引擎/规则版本、verdict 与发布 CAS；压缩包再检查具体 entry 和触发的资源上限。审计记录主体、动作、对象 ID、策略版本和结果，不记录签名 query、正文或未经处理的敏感文件名。</p><h2 id="_17-s3兼容实现边界" tabindex="-1">17. S3兼容实现边界 <a class="header-anchor" href="#_17-s3兼容实现边界" aria-label="Permalink to &quot;17. S3兼容实现边界&quot;">​</a></h2><ol><li>Quarantine 必须由 bucket policy、独立 bucket 或拒绝读取的访问路径落实，不能只靠应用状态字段。</li><li>类型识别需要读取足够的文件头和内部结构；验证对象存储的 range GET、最大扫描大小与流式读取行为。</li><li>保存明确的 checksum 与 object version，避免扫描任务读取到同 key 后写入的新内容。</li><li>对象事件可能重复、延迟或乱序；消费者以 version/generation 幂等，事件只触发工作而不作为发布事实。</li><li>扫描服务账号只读 quarantine、只写受控结果；若对象加密，单独配置最小 KMS 解密权限。</li><li>从 quarantine 到 clean 若通过 copy/tag 完成，要验证复制后的 checksum/version，并用数据库条件更新发布。</li><li>生命周期不能在法务保留、人工复核或恶意样本调查结束前删除证据；不同 verdict 使用不同保留期。</li><li>压缩包解析在隔离运行时执行，临时目录按 job ID 分配并在成功、失败和进程崩溃后都可回收。</li><li>扫描和导入都要覆盖超时、资源耗尽、损坏文件与引擎崩溃，失败状态不能自动转为允许下载。</li><li>审计导出与对象枚举必须正确处理分页，并定期对账 clean 对象、业务引用和扫描记录是否一一对应。</li></ol><h2 id="_18-生产检查" tabindex="-1">18. 生产检查 <a class="header-anchor" href="#_18-生产检查" aria-label="Permalink to &quot;18. 生产检查&quot;">​</a></h2><ol><li>存储策略直接拒绝读取 quarantine 对象，应用路由遗漏也不能绕过隔离。</li><li>上传入口同时限制声明大小、实际读取字节、速率和租户配额，超限立即终止流。</li><li>类型判定覆盖扩展名、Content-Type、magic 与内部结构，不一致结果按拒绝策略处理。</li><li>scanner 读取精确 object version，结果记录引擎、规则、签名库版本和完成时间。</li><li>timeout、崩溃或未知 verdict 保持 quarantine，只有匹配 generation 的 clean 结果可以发布。</li><li>EICAR、宏文档、伪扩展、损坏文件与 active content 测试集在扫描升级后回归。</li><li>压缩包在隔离环境流式解析，文件数、层数、展开字节、压缩比与路径规则逐 entry 生效。</li><li>下载每次重新授权；跨 tenant、旧 worker、旧 version 和被撤权用户的拒绝路径已验证。</li><li>审计能关联上传、扫描、发布、下载与删除，同时避免记录正文、签名和敏感原始文件名。</li><li>quarantine 保留、人工复核、恶意证据和隐私删除的优先级及执行期限已经演练。</li></ol><h2 id="_19-综合练习与验收" tabindex="-1">19. 综合练习与验收 <a class="header-anchor" href="#_19-综合练习与验收" aria-label="Permalink to &quot;19. 综合练习与验收&quot;">​</a></h2><p>实现“企业附件上传”并用“压缩包导入”验证不同约束。提交状态机、策略、对象清单、失败注入和观测面板。</p><ul><li>[ ] 大小限制 的正常、边界、权限和失败路径均通过。</li><li>[ ] 文件名 的正常、边界、权限和失败路径均通过。</li><li>[ ] Content-Type 的正常、边界、权限和失败路径均通过。</li><li>[ ] Magic/结构 的正常、边界、权限和失败路径均通过。</li><li>[ ] Quarantine 的正常、边界、权限和失败路径均通过。</li><li>[ ] Malware scan 的正常、边界、权限和失败路径均通过。</li><li>[ ] Archive safety 的正常、边界、权限和失败路径均通过。</li><li>[ ] Active content 的正常、边界、权限和失败路径均通过。</li><li>[ ] 两个完整案例都可在隔离环境重复运行。</li><li>[ ] 对象存储故障不改变数据库业务不变量。</li><li>[ ] 所有孤儿、版本、parts和审计记录有保留/清理策略。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://cheatsheetseries.owasp.org/cheatsheets/File_Upload_Cheat_Sheet.html" target="_blank" rel="noreferrer">OWASP File Upload Cheat Sheet</a>（访问日期：2026-07-17）</li><li><a href="https://docs.aws.amazon.com/AmazonS3/latest/userguide/security-best-practices.html" target="_blank" rel="noreferrer">AWS S3 security best practices</a>（访问日期：2026-07-17）</li><li><a href="https://docs.aws.amazon.com/prescriptive-guidance/latest/presigned-url-best-practices/introduction.html" target="_blank" rel="noreferrer">AWS S3 presigned URL best practices</a>（访问日期：2026-07-17）</li><li><a href="https://www.cisa.gov/resources-tools/services/malware-analysis" target="_blank" rel="noreferrer">CISA Malware Analysis</a>（访问日期：2026-07-17）</li><li><a href="https://www.rfc-editor.org/rfc/rfc9110.html" target="_blank" rel="noreferrer">RFC 9110 Content-Disposition references</a>（访问日期：2026-07-17）</li></ul>`,117)])])}const b=e(n,[["render",l]]);export{u as __pageData,b as default};
